  const pageBody = pages[idx] || {};
  const pageDeals = Array.isArray(pageBody.data) ? pageBody.data : [];
  const candidateTotal = Number(pageBody.totalCount);

  if (totalCount === null && Number.isFinite(candidateTotal)) {
    totalCount = candidateTotal;
  }

  deals.push(...pageDeals);
  pageStats.push({
    page: idx + 1,
    page_count: pageDeals.length
  });
}

if (totalCount === null) {
  totalCount = 0;
}

