      passed: deals.length === totalCount
    }
  }
}];

const input = $json || {};
const nowIso = String(input.run_at || new Date().toISOString());
const nowTs = Date.parse(nowIso);

if (!Number.isFinite(nowTs)) {
  throw new Error(`run_at invalido: ${input.run_at}`);
}

const rules = Array.isArray(input.sla_rules) ? input.sla_rules.filter((rule) => {
  const validMinutes = Number.isFinite(Number(rule?.target_minutes)) && Number(rule.target_minutes) >= 0;
  return Boolean(rule?.active) && typeof rule?.from_stage_id === 'string' && rule.from_stage_id && validMinutes;
}) : [];

if (!rules.length) {
  throw new Error('Nenhuma regra SLA ativa encontrada em sla_rules.');
}

const rulesByStage = new Map();
for (const rule of rules) {
  rulesByStage.set(rule.from_stage_id, {
    ...rule,
    target_minutes: Number(rule.target_minutes)
  });
}

function getFirstText(values) {
  for (const value of values) {
    if (value === undefined || value === null) {
      continue;
    }

    const text = String(value).trim();
    if (text) {
      return text;
    }
  }

  return null;
}

function resolveDealName(deal) {
  return getFirstText([
    deal?.title,
    deal?.name,
    deal?.contact?.name,
    deal?.contact?.email,
    deal?.fields?.name,
    deal?.fields?.nome,
    deal?.fields?.lead_name,
    deal?.fields?.lead_nome
  ]);
}

function parseReferenceTs(deal) {
  const updatedStageTs = Date.parse(String(deal?.updated_stage_at || ''));
  if (Number.isFinite(updatedStageTs)) {
    return {
      reference_ts: new Date(updatedStageTs).toISOString(),
      reference_source: 'updated_stage_at',
      reference_epoch_ms: updatedStageTs
    };
  }

  const createdTs = Date.parse(String(deal?.created_at || ''));
  if (Number.isFinite(createdTs)) {
    return {
      reference_ts: new Date(createdTs).toISOString(),
      reference_source: 'created_at',
      reference_epoch_ms: createdTs
    };
  }

  return null;
}

function computeDealSla(deal, nowEpochMs) {
  if (String(deal?.status || '').toUpperCase() !== 'OPEN') {
    return null;
  }

  const stageId = String(deal?.stage_id || '').trim();
  if (!stageId || stageId === String(input.closing_stage_id || '')) {
    return null;
  }

  const rule = rulesByStage.get(stageId);
  if (!rule) {
    return null;
  }

  const reference = parseReferenceTs(deal);
  if (!reference) {
    return {
      deal_id: deal?.id || null,
      status: 'invalid_reference_ts',
      stage_id: stageId,
      stage_label: deal?.stage || rule.from_stage_label || '',
      target_minutes: rule.target_minutes,
      priority: rule.priority || 'medium'
    };
  }

  const ageMinutes = Math.floor((nowEpochMs - reference.reference_epoch_ms) / 60000);
  const overdueMinutes = ageMinutes - rule.target_minutes;

  return {
    deal_id: deal?.id || null,
    deal_name: resolveDealName(deal),
    contact_name: deal?.contact?.name || null,
    contact_email: deal?.contact?.email || null,
    user_id: deal?.user?.id || null,
    user_name: deal?.user?.name || deal?.user?.full_name || null,
    status: 'computed',
    stage_id: stageId,
    stage_label: deal?.stage || rule.from_stage_label || '',
    to_stage_id: rule.to_stage_id,
    to_stage_label: rule.to_stage_label,
    target_minutes: rule.target_minutes,
    age_minutes: ageMinutes,
    overdue_minutes: overdueMinutes,
    is_overdue: overdueMinutes > 0,
    reference_ts: reference.reference_ts,
    reference_source: reference.reference_source,
    priority: rule.priority || 'medium'
  };
}

function evaluateTestCases() {
  const fixedNow = Date.parse('2026-03-06T15:00:00.000Z');
  const firstRule = rules[0];

  const overdueDeal = {
    id: 'test-overdue',
    status: 'OPEN',
    stage_id: firstRule.from_stage_id,
    stage: firstRule.from_stage_label,
    title: 'Deal de teste com titulo',
    updated_stage_at: '2026-03-05T14:59:00.000Z',
    created_at: '2026-03-05T14:59:00.000Z'
  };

  const onTimeDeal = {
    id: 'test-on-time',
    status: 'OPEN',
    stage_id: firstRule.from_stage_id,
    stage: firstRule.from_stage_label,
    title: 'Deal no prazo',
    updated_stage_at: '2026-03-06T03:30:00.000Z',
    created_at: '2026-03-06T03:30:00.000Z'
  };

  const fallbackDeal = {
    id: 'test-fallback',
    status: 'OPEN',
    stage_id: firstRule.from_stage_id,
    stage: firstRule.from_stage_label,
    contact: {
      name: 'Contato fallback'
    },
    updated_stage_at: null,
    created_at: '2026-03-05T10:00:00.000Z'
  };

  const overdueResult = computeDealSla(overdueDeal, fixedNow);
  const onTimeResult = computeDealSla(onTimeDeal, fixedNow);
  const fallbackResult = computeDealSla(fallbackDeal, fixedNow);

  const assertions = [
    {
      name: 'marca deal atrasado corretamente',
      passed: Boolean(overdueResult && overdueResult.is_overdue === true && overdueResult.overdue_minutes > 0)
    },
    {
      name: 'nao marca deal dentro do SLA',
      passed: Boolean(onTimeResult && onTimeResult.is_overdue === false && onTimeResult.overdue_minutes <= 0)
    },
    {
      name: 'usa fallback created_at quando updated_stage_at ausente',
      passed: Boolean(fallbackResult && fallbackResult.reference_source === 'created_at')
    },
    {
      name: 'resolve nome do deal por title quando disponivel',
      passed: Boolean(overdueResult && overdueResult.deal_name === 'Deal de teste com titulo')
    },
    {
      name: 'resolve nome do deal pelo contato quando title e name ausentes',
      passed: Boolean(fallbackResult && fallbackResult.deal_name === 'Contato fallback')
    }
  ];

  const failed = assertions.filter((item) => !item.passed);
  if (failed.length) {
    const names = failed.map((item) => item.name).join('; ');
    throw new Error(`Falha na validacao T3: ${names}`);
  }

  return {
    fixed_now: new Date(fixedNow).toISOString(),
    assertions
  };
}

const dealList = Array.isArray(input.deals) ? input.deals : [];
const computed = [];
const invalidReferences = [];
const overdueDeals = [];

for (const deal of dealList) {
  const result = computeDealSla(deal, nowTs);
  if (!result) {
    continue;
  }

  if (result.status === 'invalid_reference_ts') {
    invalidReferences.push(result);
    continue;
  }

  computed.push(result);
  if (result.is_overdue) {
    overdueDeals.push(result);
  }
}




if (Boolean(input.force_fake_overdue_test)) {
  const sellerList = Array.isArray(input?.routing?.sellers)
    ? input.routing.sellers.filter((seller) => seller?.active !== false && seller?.user_id)
