      deal_name: 'Lead Fake B1',
      user_id: sellerB?.user_id || null,
      user_name: sellerB?.seller_label || 'Sem responsavel',
      stage_id: stageA.from_id,
      stage_label: stageA.from,
      to_stage_id: stageA.to_id,
