      stage_id: stageB.from_id,
      stage_label: stageB.from,
      to_stage_id: stageB.to_id,
      to_stage_label: stageB.to,
      overdue_minutes: 130
    }
  ];

  for (const fake of fakeDeals) {
    overdueDeals.push({
      deal_id: fake.deal_id,
