  }
}

const testValidation = evaluateTestCases();

return [{
  json: {
    ...input,
    sla: {
      active_rules_count: rules.length,
      computed_count: computed.length,
      overdue_count: overdueDeals.length,
      invalid_reference_count: invalidReferences.length,
      overdue_deals: overdueDeals,
      computed_deals: computed,
      invalid_reference_deals: invalidReferences,
      tests: testValidation
    }
  }
}];

const input = $json || {};
const overdueDeals = Array.isArray(input?.sla?.overdue_deals) ? input.sla.overdue_deals : [];

const fallback = input?.routing?.fallback || {
  key: 'sem_responsavel',
  label: 'Sem responsavel',
  slack_channel: 'comercial-bot'
};

const sellers = Array.isArray(input?.routing?.sellers)
  ? input.routing.sellers.filter((seller) => seller?.active !== false && seller?.user_id)
  : [];

const routeByUser = new Map();
for (const seller of sellers) {
  routeByUser.set(String(seller.user_id), seller);
}

const groupsByKey = new Map();

function ensureGroup(key, metadata) {
  if (!groupsByKey.has(key)) {
    groupsByKey.set(key, {
      key,
      user_id: metadata.user_id || null,
      seller_label: metadata.seller_label || null,
      slack_channel: metadata.slack_channel || null,
      is_fallback: Boolean(metadata.is_fallback),
      deals: []
    });
  }
  return groupsByKey.get(key);
}

ensureGroup(String(fallback.key || 'sem_responsavel'), {
  user_id: null,
  seller_label: fallback.label || 'Sem responsavel',
  slack_channel: fallback.slack_channel || 'comercial-bot',
  is_fallback: true
});

for (const deal of overdueDeals) {
  const userId = String(deal?.user_id || '').trim();
  const route = userId ? routeByUser.get(userId) : null;

  if (route) {
    const group = ensureGroup(userId, {
      user_id: route.user_id,
      seller_label: route.seller_label || deal.user_name || null,
      slack_channel: route.slack_channel || null,
      is_fallback: false
    });
    group.deals.push(deal);
    continue;
  }

  const fallbackKey = String(fallback.key || 'sem_responsavel');
  const fallbackGroup = ensureGroup(fallbackKey, {
    user_id: null,
    seller_label: fallback.label || 'Sem responsavel',
    slack_channel: fallback.slack_channel || 'comercial-bot',
    is_fallback: true
  });
  fallbackGroup.deals.push(deal);
}

const groups = Array.from(groupsByKey.values())
  .map((group) => ({
    ...group,
    total_overdue: group.deals.length
  }))
  .sort((a, b) => b.total_overdue - a.total_overdue);

const groupedDealIds = groups.flatMap((group) => group.deals.map((deal) => String(deal.deal_id || ''))).filter(Boolean);
const overdueDealIds = overdueDeals.map((deal) => String(deal.deal_id || '')).filter(Boolean);

const uniqueGrouped = new Set(groupedDealIds);
const uniqueOverdue = new Set(overdueDealIds);

const acceptancePassed = groupedDealIds.length === overdueDealIds.length
  && uniqueGrouped.size === uniqueOverdue.size
  && Array.from(uniqueOverdue).every((id) => uniqueGrouped.has(id));

if (!acceptancePassed) {
  throw new Error('Falha na validacao T4: deals atrasados nao estao mapeados de forma unica por grupo.');
}

return [{
  json: {
    ...input,
    grouped: {
      total_groups: groups.length,
      total_overdue: overdueDeals.length,
      sem_responsavel_count: (groups.find((group) => group.is_fallback) || { total_overdue: 0 }).total_overdue,
      groups,
      acceptance_t4: {
        criterion: 'cada deal atrasado aparece em apenas 1 grupo',
        passed: acceptancePassed
      }
    }
  }
}];

const baseInput = (() => {
  try {
    return $('Code - Build Slack Payload').first().json || {};
  } catch (error) {
    return $json || {};
  }
})();

const input = baseInput;
const sla = input.sla || {};
const grouped = input.grouped || {};
const slackPayload = input.slack_payload || {};

function safeAll(nodeName) {
  try {
    return $(nodeName).all();
  } catch (error) {
    return [];
  }
}

function redactErrorMessage(value) {
  const text = String(value || '').trim();
  if (!text) {
    return 'erro_sem_detalhe';
  }
  return text
    .replace(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/gi, '[redacted_email]')
    .replace(/\+?\d{10,15}/g, '[redacted_phone]')
    .slice(0, 180);
}

const dryRun = Boolean(input.dry_run);
const messages = Array.isArray(slackPayload.messages) ? slackPayload.messages : [];
const messagesReady = Number(slackPayload.total_messages || 0);

const slackExecutions = safeAll('Slack - Send Message');
const snapshotInsertions = safeAll('Data Table - Insert Overdue Snapshots');

let messagesSent = 0;
let messagesFailed = 0;
const failedDeliveries = [];

if (!dryRun && messagesReady > 0) {
  for (let index = 0; index < slackExecutions.length; index += 1) {
    const item = slackExecutions[index] || {};
    const hasError = Boolean(item?.error || item?.json?.error);

    if (hasError) {
      messagesFailed += 1;
      const pairedIndex = Number.isInteger(item?.pairedItem?.item) ? item.pairedItem.item : index;
      const sourceMessage = messages[pairedIndex] || null;
      failedDeliveries.push({
        group_key: sourceMessage?.group_key || null,
        channel: sourceMessage?.channel || null,
        reason: redactErrorMessage(item?.error?.message || item?.json?.error?.message || item?.json?.error || item?.error)
      });
      continue;
    }

    messagesSent += 1;
  }

  const accounted = messagesSent + messagesFailed;
  if (accounted < messagesReady) {
    const missing = messagesReady - accounted;
    messagesFailed += missing;
    for (let idx = 0; idx < missing; idx += 1) {
      const sourceMessage = messages[accounted + idx] || null;
      failedDeliveries.push({
        group_key: sourceMessage?.group_key || null,
        channel: sourceMessage?.channel || null,
        reason: 'resultado_envio_nao_retorno'
      });
    }
  }
}

const plannedSnapshots = dryRun ? 0 : (Array.isArray(sla.overdue_deals) ? sla.overdue_deals.length : 0);
const snapshotsInserted = dryRun
  ? 0
  : snapshotInsertions.reduce((sum, item) => {
      const inserted = Number(item?.json?.insertedRows);
      if (Number.isFinite(inserted) && inserted >= 0) {
        return sum + inserted;
      }
      return sum + 1;
    }, 0);

const startedAtIso = String(input.run_at || '');
const startedAtMs = Date.parse(startedAtIso);
const finishedAtIso = new Date().toISOString();
const finishedAtMs = Date.parse(finishedAtIso);
const durationMs = Number.isFinite(startedAtMs) && Number.isFinite(finishedAtMs)
  ? Math.max(0, finishedAtMs - startedAtMs)
  : null;

const acceptanceT3 = {
  criterion: 'cenarios de teste marcam corretamente atraso e nao atraso',
  passed: Array.isArray(sla?.tests?.assertions) ? sla.tests.assertions.every((item) => item.passed) : false,
  assertions: sla?.tests?.assertions || []
};

const acceptanceT4 = grouped?.acceptance_t4 || {
  criterion: 'cada deal atrasado aparece em apenas 1 grupo',
  passed: false
};

const acceptanceT5 = slackPayload?.acceptance_t5 || {
  criterion: 'mensagem contem nome do deal, fase atual, proxima fase e atraso',
  passed: false,
  violations: []
};

const acceptanceT7 = {
  criterion: 'falha parcial de envio nao interrompe run completo',
  passed: dryRun || (messagesReady === (messagesSent + messagesFailed)),
  failed_deliveries: failedDeliveries
};

const acceptanceT8 = {
  criterion: 'mensagens corretas por vendedora e persistencia confirmada',
  passed: Boolean(acceptanceT5.passed) && (dryRun || snapshotsInserted === plannedSnapshots),
  checks: {
    dry_run: dryRun,
    slack_payload_ok: Boolean(acceptanceT5.passed),
    snapshots_persisted_ok: dryRun ? true : snapshotsInserted === plannedSnapshots
  }
};

const status = messagesFailed > 0 ? 'partial_success' : 'success';

return [{
  json: {
    status,
    step: 'T7/T8 - Observabilidade, falha controlada e readiness',
    run_id: input.run_id,
    origin_id: input.origin_id,
    started_at: startedAtIso || null,
    finished_at: finishedAtIso,
    duration_ms: durationMs,
    total_open: Number(input.total_count || 0),
    collected_count: Number(input.collected_count || 0),
    pages_read: Number(input.page_count || 0),
    total_overdue: Number(sla.overdue_count || 0),
    acceptance_t2: input.acceptance,
    acceptance_t3: acceptanceT3,
    acceptance_t4: acceptanceT4,
    acceptance_t5: acceptanceT5,
    acceptance_t7: acceptanceT7,
    acceptance_t8: acceptanceT8,
    sla_stats: {
      active_rules_count: Number(sla.active_rules_count || 0),
      computed_count: Number(sla.computed_count || 0),
      overdue_count: Number(sla.overdue_count || 0),
      invalid_reference_count: Number(sla.invalid_reference_count || 0)
    },
    grouped_stats: {
      total_groups: Number(grouped.total_groups || 0),
      total_overdue: Number(grouped.total_overdue || 0),
      sem_responsavel_count: Number(grouped.sem_responsavel_count || 0)
    },
    slack_stats: {
      messages_ready: messagesReady,
      messages_sent: messagesSent,
      messages_failed: messagesFailed,
      channels_ready: Number(slackPayload.total_channels || 0),
      dry_run: dryRun
    },
    snapshot_stats: {
      planned_rows: plannedSnapshots,
      inserted_rows: snapshotsInserted
    },
    log_summary: {
      total_open: Number(input.total_count || 0),
      total_overdue: Number(sla.overdue_count || 0),
      messages_sent: messagesSent,
      messages_failed: messagesFailed
    },
    messages_targets: messages.map((msg) => ({
      group_key: msg.group_key || null,
      channel: msg.channel || null,
      total_overdue: Number(msg.total_overdue || 0)
    }))
  }
}];

const input = $json || {};
const groups = Array.isArray(input?.grouped?.groups) ? input.grouped.groups : [];

function fmtMinutes(totalMinutes) {
  const value = Number(totalMinutes);
  if (!Number.isFinite(value)) return '-';
  const abs = Math.abs(Math.trunc(value));
  const h = Math.floor(abs / 60);
  const m = abs % 60;
  return h > 0 ? `${h}h ${m}m` : `${m}m`;
}

const messages = [];
const violations = [];
const separator = '────────────────────────';

for (const group of groups) {
  const deals = Array.isArray(group?.deals) ? group.deals : [];
  if (!deals.length) {
    continue;
  }

  const channel = group?.slack_channel || input?.routing?.fallback?.slack_channel || 'comercial-bot';
  const sellerLabel = group?.seller_label || group?.key || 'sem_responsavel';
  const isFallback = Boolean(group?.is_fallback);

  const titleRaw = isFallback
    ? 'SLA Diario | Deals atrasados sem responsavel'
    : `SLA Diario | Deals atrasados de ${sellerLabel}`;

  const title = `\`${titleRaw}\``;

  const textLines = [
    title,
    `*Total atrasados:* ${deals.length}`,
    ''
  ];

  const blockLines = [...textLines];

  for (const deal of deals) {
    const dealName = deal?.deal_name || deal?.contact_name || '(sem nome)';
    const stage = deal?.stage_label || '(sem fase atual)';
    const nextStage = deal?.to_stage_label || '(sem proxima fase)';
    const overdue = fmtMinutes(deal?.overdue_minutes);
    const isUsingIdAsName = String(dealName) === String(deal?.deal_id || '');

    const line = `• *${dealName}* | *Fase Atual:* ${stage} | *Proxima Fase:* ${nextStage} | *Atraso:* ${overdue}`;

    textLines.push(line);
    blockLines.push(line);

    const hasAllFields = Boolean(dealName && stage && nextStage && overdue !== '-' && !isUsingIdAsName);

    if (!hasAllFields) {
      violations.push({
        group_key: group?.key || null,
        deal_id: deal?.deal_id || null,
        reason: isUsingIdAsName ? 'deal_name_is_id' : 'missing_required_fields'
      });
    }
  }

  textLines.push('', separator);
  blockLines.push('', separator);

  messages.push({
    group_key: group?.key || null,
    user_id: group?.user_id || null,
    seller_label: sellerLabel,
    is_fallback: isFallback,
    channel,
    total_overdue: deals.length,
    text: textLines.join('\n'),
    blocks: [
      {
        type: 'section',
        text: {
          type: 'mrkdwn',
          text: blockLines.join('\n')
        }
      }
    ],
    deals
  });
}

return [{
  json: {
    ...input,
    slack_payload: {
      total_messages: messages.length,
      total_channels: new Set(messages.map((msg) => msg.channel)).size,
      messages,
      acceptance_t5: {
        criterion: 'mensagem contem nome do deal, fase atual, proxima fase e atraso',
        passed: violations.length === 0,
        violations
      }
    }
  }
}];

const input = $json || {};
const dryRun = Boolean(input.dry_run);
if (dryRun) {
  return [];
}

const messages = Array.isArray(input?.slack_payload?.messages) ? input.slack_payload.messages : [];

return messages.map((msg) => ({
  json: {
    run_id: input.run_id,
    group_key: msg.group_key || null,
    seller_label: msg.seller_label || null,
    channel: msg.channel || '',
    text: msg.text || ''
  }
}));

const input = $json || {};

if (Boolean(input.dry_run)) {
  return [];
}

const overdueDeals = Array.isArray(input?.sla?.overdue_deals) ? input.sla.overdue_deals : [];

return overdueDeals.map((deal) => ({
  json: {
    run_id: input.run_id || null,
    deal_id: deal?.deal_id || null,
    origin_id: input.origin_id || null,
    stage_id: deal?.stage_id || null,
    stage_label: deal?.stage_label || null,
    deal_status: 'OPEN',
    close_bucket: null,
    user_id: deal?.user_id || null,
    seller_label: deal?.user_name || null,
    contact_id: null,
    contact_name: deal?.contact_name || null,
    contact_email: deal?.contact_email || null,
    latest_meeting_datetime: null,
    latest_meeting_link: null,
    reference_ts: deal?.reference_ts || null,
    age_minutes: Number.isFinite(Number(deal?.age_minutes)) ? Number(deal.age_minutes) : null,
    target_minutes: Number.isFinite(Number(deal?.target_minutes)) ? Number(deal.target_minutes) : null,
    overdue_minutes: Number.isFinite(Number(deal?.overdue_minutes)) ? Number(deal.overdue_minutes) : null,
    priority: deal?.priority || 'medium',
    payload_json: JSON.stringify(deal || null),
    created_at: new Date().toISOString()
  }
}));

const input = $json || {};
const shouldTrigger = Boolean(input.dry_run) || Number(input?.slack_payload?.total_messages || 0) === 0;
if (!shouldTrigger) {
  return [];
}
return [{ json: { trigger: 'no_slack_dispatch' } }];
